"""Person-free within-match tactical adjustment-speed concepts for Tennis."""
SPORT = "Tennis"
FAMILY = "AdjustmentSpeed"
CONCEPTS: list[dict] = [
    {"slug":"pattern_solve_latency","title":"Pattern-Solve Latency",
     "summary":"Tracks how many repeated exposures to a winning opponent pattern occur before a player begins effectively neutralizing it; expressed as exploited-repetitions-before-counter within a match.",
     "stat_signature":"Median exploited reps before effective counter: 4-8 on first exposure; drops to 2-4 after the first set when the same pattern recurs; counter-effectiveness threshold = 5 pp lift in points-won on that pattern.",
     "mechanism":"Recognizing a pattern requires accumulating enough evidence to override a default reply; pattern-solve latency reflects the cognitive cost of re-routing a well-rehearsed motor response while simultaneously executing under match pressure.",
     "conditions":"Longer latency against serve-dominant patterns where pace compresses decision time; shorter latency on longer rallies where the ball speed allows mid-exchange read; clay slows the ball and shortens solve latency by 1-2 reps.",
     "magnitude":"Players with latency <=3 reps concede 6-12 fewer points on a newly introduced pattern per set compared with players averaging 6+ reps; the gap is largest in the second set when the opponent still has initiative.",
     "links":["mid_match_problem_diagnosis_speed","serve_pattern_break_speed","tactical_shift_between_sets","pattern_persistence_after_failure"]},

    {"slug":"return_position_adjustment_speed","title":"Return-Position Adjustment Speed",
     "summary":"Measures how quickly a returner shifts depth or lateral starting position after a serve pattern repeatedly beats them, expressed as service points conceded before return-position drift is observable.",
     "stat_signature":"Observable drift threshold: average contact depth shifts >=0.5 m or lateral start moves >=0.4 m; median adjustment onset: 3-6 service points on the same pattern; early adjusters (<=3 points) show >=6 pp recovery in return-points-won.",
     "mechanism":"A fixed return position optimized for one serve shape becomes a vulnerability when that shape dominates; positional drift resets the angle-reaction window and recovers partial neutralization even before a full tactical change.",
     "conditions":"Most relevant against heavy kick serves on the ad-court backhand (deep position response) and against wide deuce-court flat serves (lateral start shift); applies in second-serve situations when the server exploits a static setup.",
     "magnitude":"Returners adjusting within 4 service points recover 4-9 pp in return-points-won versus those maintaining position through 8+ exposures; the effect is largest when serve speed exceeds 185 km/h.",
     "links":["pattern_solve_latency","court_positioning_depth_correction","serve_pattern_break_speed","return_chip_to_drive_switch"]},

    {"slug":"serve_pattern_break_speed","title":"Serve-Pattern Break Speed",
     "summary":"Captures how fast a server abandons a predictable placement once the returner has read and punished it, measured as read-and-punished serves before the placement distribution meaningfully changes.",
     "stat_signature":"Read-and-punished threshold: return-winner or forced-error on >=35% of serves to one zone; break speed = number of additional serves to that zone before zone share drops >=10 pp; fast servers break in <=3 additional serves.",
     "mechanism":"Continuing a successful returner read donates initiative; a fast pattern break reloads unpredictability before the returner consolidates the advantage into a game-level trend; slow breakers allow the returner to lock into an anticipatory stance.",
     "conditions":"Break speed matters most on second serves where predictability is higher; also relevant when a wide T deuce-court serve is read on consecutive deuce points; surfaces with consistent bounce (hard courts) amplify predictability, raising urgency.",
     "magnitude":"Servers breaking within 3 punished serves avoid a sustained return-winner run; servers taking 6+ serves to break the pattern concede 5-10 extra return-aggressive points per set on the exploited zone.",
     "links":["pattern_solve_latency","second_serve_target_adjustment_speed","return_position_adjustment_speed","serve_placement_remix_after_being_read"]},

    {"slug":"tactical_shift_between_sets","title":"Between-Sets Tactical Shift Magnitude",
     "summary":"Quantifies how sharply a player changes patterns after dropping a set, measured by rally-shape, serve-mix, and court-position delta in the opening games of the next set.",
     "stat_signature":"Serve-placement entropy delta >=0.12 bits; serve-zone share change in any zone >=10 pp; rally-direction share to the dominant wing shifts >=8 pp; measured across the first three service games of the new set.",
     "mechanism":"A lost set signals that the current tactical profile is deciphered; resetting patterns in the opening games of the next set exploits the opponent's expectation carry-over before they can recalibrate; the first two games have the highest carry-over susceptibility.",
     "conditions":"Most impactful in best-of-five formats with a rest between sets; less decisive when the set loss was caused by unforced errors rather than tactical exploitation; clay surfaces provide a longer adjustment window due to slower between-point tempo.",
     "magnitude":"Players executing a >=10 pp serve-mix shift at set start show 5-11 pp higher serve-points-won in the opening two games before the opponent registers the new distribution; the advantage diminishes by games 4-5 as recalibration occurs.",
     "links":["between_set_pattern_overhaul","pattern_solve_latency","deciding_set_adaptation_speed","first_strike_aggression_recalibration"]},

    {"slug":"rally_length_recalibration_speed","title":"Rally-Length Recalibration Speed",
     "summary":"Measures how quickly a player shifts toward shortening or extending rallies once the current rally length is producing unfavorable outcomes, expressed as games before the average rally-length trend reverses.",
     "stat_signature":"Unfavorable threshold: points-won in the current rally-length band drops below 44% for two consecutive games; recalibration speed = games elapsed before average rally length shifts >=1.5 shots; fast recalibrators respond within 1-2 games.",
     "mechanism":"Rally-length optimization aligns risk exposure to a player's physical and technical strengths; missing the shift extends a losing stretch by continuing to play into the opponent's dominant range.",
     "conditions":"Shortening applies against high-consistency defenders where long rallies favor the opponent's error-floor advantage; extending applies against aggressive first-strike opponents whose forced-error rate drops on longer exchanges.",
     "magnitude":"Players recalibrating within 2 games recover 4-8 pp in points-won versus those persisting in the unfavorable band for 4+ games; the rally-length sweet spot accounts for 6-10 pp of baseline point-win rate variation.",
     "links":["shot_tolerance_and_patience_shift","pattern_solve_latency","tactical_shift_between_sets","anti_pace_neutralization_speed"]},

    {"slug":"second_serve_target_adjustment_speed","title":"Second-Serve Target Adjustment Speed",
     "summary":"Captures how fast a server relocates the second-serve target after the returner consistently attacks it, measured as punished second serves before placement density at that zone drops meaningfully.",
     "stat_signature":"Attack threshold: return-aggression index >=62% on serves to a single zone; adjustment speed = punished second serves before zone share drops >=12 pp; fast adjusters respond within 3 attacked serves.",
     "mechanism":"A predictable second-serve target allows the returner to pre-load an aggressive setup; relocating the zone forces the returner to reconsider their position and aggression set-up, recovering a defensive margin.",
     "conditions":"Most relevant on the ad-court backhand zone exploited by inside-out return aggression; also applies when a body serve is stepped around by an aggressive forehander; surfaces with low bounce limit kick effectiveness and raise the cost of a static zone.",
     "magnitude":"Fast-adjusting servers recover 5-10 pp in second-serve-points-won within the same game versus servers maintaining the exploited zone for 6+ consecutive second serves.",
     "links":["serve_pattern_break_speed","serve_speed_versus_spot_tradeoff_shift","second_serve_aggression_recalibration"]},

    {"slug":"weakness_targeting_ramp_speed","title":"Weakness-Targeting Ramp Speed",
     "summary":"Measures how quickly a player escalates the share of balls directed at an identified weaker wing once it shows vulnerability, expressed as games-to-peak-targeting-rate after the vulnerability is first registered.",
     "stat_signature":"Vulnerability threshold: weaker-wing error-plus-short-ball rate >=42% across >=15 balls in the first set; ramp speed = games from first registration to peak targeting share; fast ramp <=2 games; peak = >=55% of groundstroke exchanges routing to that wing.",
     "mechanism":"Delaying the escalation after identifying a vulnerability donates extended recovery time and allows defensive repositioning; rapid ramp denies the opponent an adjustment window before the pattern is fully embedded.",
     "conditions":"Fastest ramp on clay where patterns compound into positional fatigue; ramp delayed on hard courts when the opponent can reliably run around a weaker wing via footwork; less effective against two-handed backhands with minimal altitude vulnerability.",
     "magnitude":"Players ramping to peak targeting within 2 games of identification reach >=55% routing share by the second set; those taking 4+ games allow the opponent to pre-compensate, reducing the short-ball yield by 5-9 pp.",
     "links":["target_the_weaker_wing_escalation","pattern_solve_latency","high_ball_to_one_handed_backhand_exploit","net_approach_frequency_response"]},

    {"slug":"net_approach_frequency_response","title":"Net-Approach Frequency Response Speed",
     "summary":"Captures how fast a player adds or cuts net approaches after passing-shot outcomes or baseline attrition signals change their value, measured by within-match approach-rate drift after a trigger event.",
     "stat_signature":"Trigger: passing conversion conceded exceeds 45% over 8+ approach points, or opponent lateral recovery time rises >=0.12 s per meter; response speed = games before approach rate changes >=5 pp; fast responders adjust within 1-2 games.",
     "mechanism":"Net approaches have high point-value when the opponent is stretched; they become liabilities when the opponent's passing line is grooved; fast response preserves the approach as a tactical tool rather than a patterned mistake.",
     "conditions":"Upward response fastest against deep-positioned opponents late in long sets; downward response triggered by clean passing lines on short approaches; most variable on clay where the passing angle range is widest.",
     "magnitude":"Approach frequency oscillates 6-18 pp across match context for tactically responsive players; those who do not respond accumulate 4-8 extra passing-shot opportunities conceded per set after the trigger.",
     "links":["net_approach_rate_dial","weakness_targeting_ramp_speed","drop_shot_introduction_against_deep_returner","target_a_fatiguing_movement_pattern"]},

    {"slug":"spin_and_pace_variation_response","title":"Spin-And-Pace Variation Response Speed",
     "summary":"Measures how quickly a player introduces changes in spin or pace once the opponent is timing the current ball well, expressed as clean strikes conceded before shot-variance rises measurably.",
     "stat_signature":"Timing threshold: opponent winner-plus-forced-error rate on current shot type reaches >=48% across 6+ exchanges; response speed = additional same-type balls before spin or pace shifts >=15 km/h or >=250 rpm; fast responders vary within 3 exchanges.",
     "mechanism":"Consistent spin and pace allow the opponent to pre-set their kinematic timing sequence; introducing variance disrupts this by forcing a recalculation of contact height, timing point, and swing weight within the same rally.",
     "conditions":"Most acute on clay where baseline rally exchanges are long and spin predictability builds over many contacts; on grass the serve dominates, making groundstroke variance a secondary signal.",
     "magnitude":"Introducing a >=15 km/h pace change or a >=250 rpm spin shift after the opponent has timed a pattern correlates with a 5-10 pp rise in opponent unforced errors across the following 3-4 exchanges.",
     "links":["rally_tempo_change_to_disrupt_rhythm","spin_and_height_adjustment_to_conditions","rally_length_recalibration_speed","pattern_solve_latency"]},

    {"slug":"court_positioning_depth_correction","title":"Court-Positioning Depth Correction Speed",
     "summary":"Captures how rapidly a player adjusts baseline standing depth after being pushed back or drawn short, measured as games before average contact-point depth returns to a tactical reference.",
     "stat_signature":"Drift threshold: average contact depth moves >=1.0 m from tactical default across two consecutive games; correction speed = games before it returns within 0.5 m; fast correctors return within 1-2 games; slow correctors remain displaced 3+ games.",
     "mechanism":"A displaced contact depth shifts the entire shot-production geometry: angles narrow when deep, reaction time compresses when short; failing to correct prolongs unfavorable geometry and compounds with fatigue-induced movement load.",
     "conditions":"Backward drift most common after heavy serve-plus-one patterns; forward rush most common after an opponent's short-ball run; clay amplifies backward displacement due to high-bounce patterns.",
     "magnitude":"Correcting depth within 2 games prevents a sustained 4-9 pp drop in points-won associated with non-optimal contact geometry; the correction is most valuable in service-return games where depth directly affects attack opportunity.",
     "links":["court_position_depth_adjustment","return_position_adjustment_speed","rally_length_recalibration_speed","target_a_fatiguing_movement_pattern"]},

    {"slug":"mid_match_problem_diagnosis_speed","title":"Mid-Match Problem-Diagnosis Speed",
     "summary":"Measures the lag between a losing pattern stabilizing and the first effective corrective response, expressed as consecutive lost points on the pattern before win-rate on it recovers.",
     "stat_signature":"Stabilization threshold: >=5 consecutive losses on a definable pattern; diagnosis lag = additional pattern exposures before win-rate recovers >=8 pp; fast diagnosers correct within 3 additional exposures; slow ones persist 8+.",
     "mechanism":"Effective diagnosis requires distinguishing a structural tactical problem from variance; the cost of delayed diagnosis is a compounding deficit as the opponent's confidence in the pattern grows and their execution sharpens.",
     "conditions":"Most consequential in critical games (break-point games, 5-5+) where each point carries high leverage; less decisive in early-set phases where the opponent has not yet committed fully to the pattern.",
     "magnitude":"Fast diagnosers limit a losing pattern to 5-8 lost points before correcting; slow diagnosers can surrender 10-15 consecutive pattern losses, which correlates with a 1-2 game disadvantage in game-win rate for the set.",
     "links":["pattern_solve_latency","tactical_shift_between_sets","pattern_persistence_after_failure","momentum_arrest_response_speed"]},

    {"slug":"break_point_pattern_shift_speed","title":"Break-Point Pattern Shift Speed",
     "summary":"Measures how rapidly a player alters tendencies specifically on break points after a pattern is exploited on them, expressed as break points lost on a pattern before the choice distribution changes.",
     "stat_signature":"Exploitation threshold: 2+ break points lost on the same identifiable pattern (serve zone, rally direction); shift speed = additional break points on same pattern before distribution changes >=15 pp; fast shifters change after 1-2 further exposures.",
     "mechanism":"Break points are high-leverage moments where an exploited pattern has outsized consequences; failing to shift after repeated break-point losses on a pattern surrenders a critical tactical advantage at exactly the wrong leverage point.",
     "conditions":"Most impactful at 5-5 and later in sets where break points determine set outcome; also relevant in a final deciding set where break-point conversion shapes match outcome; less consequential at 1-1 and 2-2.",
     "magnitude":"Serving players who shift within 2 break-point losses on a pattern hold serve 8-15 pp more frequently in subsequent break-point situations; those who persist on the same pattern surrender break-point conversion rates >=35%.",
     "links":["serve_pattern_break_speed","mid_match_problem_diagnosis_speed","tiebreak_pattern_adjustment_speed","momentum_arrest_response_speed"]},

    {"slug":"drop_shot_counter_speed","title":"Drop-Shot Counter Speed",
     "summary":"Captures how fast a player adjusts court position to defend repeated drop shots after early ones succeed, measured as successful drops conceded before recovery-start position moves visibly forward.",
     "stat_signature":"Repeated drop threshold: >=3 successful drop shots in a set; forward-position shift: average between-rally recovery depth moves >=0.7 m closer to net within 2 subsequent games; fast counters shift within the same game.",
     "mechanism":"A static recovery position far behind the baseline makes the drop shot structurally free; moving the recovery-start position forward removes the distance advantage but opens the lob, forcing the opponent into a more complex choice.",
     "conditions":"Most relevant on clay where heavy topspin resets players deep and the drop-shot angle is widest; less relevant on grass where service dominance reduces rally-phase drop-shot frequency.",
     "magnitude":"Advancing recovery position by >=0.7 m reduces drop-shot-point-lost rate from >=65% to <=40% by eliminating the pure-distance advantage; the trade-off is a <=12 pp increase in lob-winner conceded rate.",
     "links":["court_positioning_depth_correction","net_approach_frequency_response","drop_shot_introduction_against_deep_returner"]},

    {"slug":"pattern_persistence_after_failure","title":"Pattern Persistence After Repeated Failure",
     "summary":"Captures the inverse of adjustment speed: how many losing repetitions a player runs the same failing pattern before abandoning it, measured as median persistence-reps per distinct failing pattern.",
     "stat_signature":"Persistence score: median losing reps before a pattern's usage share drops >=10 pp; low-persistence players abandon after 3-4 losses; high-persistence players continue 7-10+ losses; measured per pattern type within a match.",
     "mechanism":"Persistence can reflect either cognitive rigidity or deliberate information-gathering; distinguishing them requires checking whether a late-pattern correction eventually produces a win-rate recovery; pure rigidity never recovers.",
     "conditions":"Highest in serve-choice patterns where between-point time is short and the decision is under pressure; lower in groundstroke patterns where longer rallies provide more tactile feedback; also elevated late in deciding sets under fatigue.",
     "magnitude":"High-persistence players (7+ reps) concede 8-14 additional unneeded losses per distinct failing pattern per set; when 2+ patterns are simultaneously failing, compound persistence cost can reach 1-2 full game equivalents.",
     "links":["mid_match_problem_diagnosis_speed","pattern_solve_latency","momentum_arrest_response_speed","tactical_shift_between_sets"]},

    {"slug":"momentum_arrest_response_speed","title":"Momentum-Arrest Response Speed",
     "summary":"Measures how quickly a player changes something tangible during an opponent's point run rather than waiting for the run to end, expressed as points-into-run before a measurable tactical choice change.",
     "stat_signature":"Run threshold: opponent wins >=3 consecutive points; response speed = additional points before a detectable change in serve zone, rally direction, or between-point time (>=4 s increase); fast responders change within 4 points of the run start.",
     "mechanism":"A momentum run creates positive-feedback reinforcement in the opponent's execution; interrupting the run early by changing tempo, target, or shot type forces re-engagement rather than exploitation of a grooved rhythm.",
     "conditions":"Most valuable in game-critical runs at 30-30, 30-40, and advantage; also relevant when the opponent begins a service hold run spanning multiple games; less decisive in early-game low-leverage runs.",
     "magnitude":"Players introducing a change within the first 4 points of a run arrest it before it reaches 6+ consecutive losses 55-65% of the time; those who wait until 6+ points are already lost face a momentum deficit that extends an average of 2.5 additional lost points.",
     "links":["mid_match_problem_diagnosis_speed","pattern_persistence_after_failure","break_point_pattern_shift_speed","between_set_pattern_overhaul"]},

    {"slug":"first_serve_percentage_management_speed","title":"First-Serve-Percentage Management Speed",
     "summary":"Measures how quickly a server trades pace for placement precision to restore first-serve percentage after a run of misses, expressed as consecutive faults before average serve speed drops detectably.",
     "stat_signature":"Miss run threshold: >=3 consecutive first-serve faults or first-serve-in rate drops below 48% across a game; speed response = faults before average serve speed drops >=7 km/h; fast managers respond within 2-3 additional serves.",
     "mechanism":"Excess pace relative to ball-placement precision causes margin loss; reducing pace by 7-12 km/h restores placement accuracy without ceding full second-serve vulnerability; a fast speed reset prevents a double-fault chain from inflating pressure.",
     "conditions":"Most relevant under fatigue when arm speed becomes inconsistent; also triggered by wind that shifts the service toss; applies more to flat-dominant servers than kick-dominant servers whose margin is spin-based.",
     "magnitude":"A targeted pace reduction of 8-12 km/h during a fault run correlates with a 10-16 pp lift in first-serve-in rate in the next 5 serves, with a marginal 2-4 km/h reply-speed reduction on recovered serves.",
     "links":["serve_pattern_break_speed","second_serve_target_adjustment_speed","serve_speed_versus_spot_tradeoff_shift"]},

    {"slug":"anti_pace_neutralization_speed","title":"Anti-Pace Neutralization Speed",
     "summary":"Captures how fast a player switches to slicing, blocking, or taking pace off when the opponent's heavy ball is converting into consistent winners, measured as pace-driven losses before low-pace shot share rises.",
     "stat_signature":"Pace-driven loss threshold: opponent winner-plus-forced-error on pace-on exchanges reaches >=52% across 8+ groundstrokes; neutralization speed = additional pace-on exchanges before slice or block share rises >=12 pp; fast neutralizers respond within 4 exchanges.",
     "mechanism":"Attempting to match heavy pace against a superior ball-striker compounds the disadvantage; absorbing pace via slice or block changes the ball's dwell time, spin direction, and trajectory, disrupting the opponent's timing and removing their energy-recycling advantage.",
     "conditions":"Most valuable on clay and medium-pace hard courts where pace-driving exchanges are sustained; less relevant on grass where serve dominance reduces rally-phase pace confrontation; applies primarily to baseline exchanges with above-baseline contact.",
     "magnitude":"Introducing a slice or block response against a pace-dominant pattern correlates with a 6-11 pp reduction in opponent winner rate over the 5-exchange window following the change; the opponent's natural adaptation takes 3-6 exchanges.",
     "links":["spin_and_pace_variation_response","rally_length_recalibration_speed","shot_tolerance_and_patience_shift","rally_tempo_change_to_disrupt_rhythm"]},
]
